const files = {"/":{"body":"<!doctype html>\n<html lang=\"tr\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n    <meta\n      name=\"description\"\n      content=\"Ali Efe'nin yazılım yolculuğundaki ilk web sitesi.\"\n    />\n    <title>Ali Efe'nin İlk Web Sitesi</title>\n    <link rel=\"stylesheet\" href=\"style.css\" />\n  </head>\n  <body>\n    <main class=\"page-shell\">\n      <section class=\"hero\" aria-labelledby=\"page-title\">\n        <p class=\"eyebrow\">ALİ EFE'NİN İLK PROJESİ • 2026</p>\n        <h1 id=\"page-title\">Merhaba, ben <span>Ali Efe.</span></h1>\n        <p class=\"intro\">\n          Yazılım öğrenmeye yeni başladım. Bu sayfa, MacBook'umla kurduğum\n          geleceğin ilk küçük adımı.\n        </p>\n\n        <button id=\"celebrate-button\" type=\"button\">\n          İlk adımı kutla\n        </button>\n        <p id=\"message\" class=\"message\" aria-live=\"polite\">\n          Butona basınca JavaScript çalışacak.\n        </p>\n      </section>\n\n      <section class=\"learning\" aria-labelledby=\"learning-title\">\n        <div class=\"section-heading\">\n          <p class=\"eyebrow\">BUGÜN ÖĞRENDİKLERİM</p>\n          <h2 id=\"learning-title\">Bir web sayfasının üç parçası</h2>\n        </div>\n\n        <div class=\"card-grid\">\n          <article class=\"card\">\n            <span class=\"number\">01</span>\n            <h3>HTML</h3>\n            <p>Sayfanın başlık, yazı ve buton gibi yapı taşlarını oluşturur.</p>\n          </article>\n\n          <article class=\"card\">\n            <span class=\"number\">02</span>\n            <h3>CSS</h3>\n            <p>Renkleri, boşlukları ve sayfanın görünümünü düzenler.</p>\n          </article>\n\n          <article class=\"card\">\n            <span class=\"number\">03</span>\n            <h3>JavaScript</h3>\n            <p>Butonlara ve diğer öğelere hareket ve davranış kazandırır.</p>\n          </article>\n        </div>\n      </section>\n    </main>\n\n    <footer>\n      <p>MacBook + merak + sabır ile hazırlandı.</p>\n    </footer>\n\n    <script src=\"script.js\"></script>\n  </body>\n</html>\n","contentType":"text/html; charset=UTF-8"},"/index.html":{"body":"<!doctype html>\n<html lang=\"tr\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n    <meta\n      name=\"description\"\n      content=\"Ali Efe'nin yazılım yolculuğundaki ilk web sitesi.\"\n    />\n    <title>Ali Efe'nin İlk Web Sitesi</title>\n    <link rel=\"stylesheet\" href=\"style.css\" />\n  </head>\n  <body>\n    <main class=\"page-shell\">\n      <section class=\"hero\" aria-labelledby=\"page-title\">\n        <p class=\"eyebrow\">ALİ EFE'NİN İLK PROJESİ • 2026</p>\n        <h1 id=\"page-title\">Merhaba, ben <span>Ali Efe.</span></h1>\n        <p class=\"intro\">\n          Yazılım öğrenmeye yeni başladım. Bu sayfa, MacBook'umla kurduğum\n          geleceğin ilk küçük adımı.\n        </p>\n\n        <button id=\"celebrate-button\" type=\"button\">\n          İlk adımı kutla\n        </button>\n        <p id=\"message\" class=\"message\" aria-live=\"polite\">\n          Butona basınca JavaScript çalışacak.\n        </p>\n      </section>\n\n      <section class=\"learning\" aria-labelledby=\"learning-title\">\n        <div class=\"section-heading\">\n          <p class=\"eyebrow\">BUGÜN ÖĞRENDİKLERİM</p>\n          <h2 id=\"learning-title\">Bir web sayfasının üç parçası</h2>\n        </div>\n\n        <div class=\"card-grid\">\n          <article class=\"card\">\n            <span class=\"number\">01</span>\n            <h3>HTML</h3>\n            <p>Sayfanın başlık, yazı ve buton gibi yapı taşlarını oluşturur.</p>\n          </article>\n\n          <article class=\"card\">\n            <span class=\"number\">02</span>\n            <h3>CSS</h3>\n            <p>Renkleri, boşlukları ve sayfanın görünümünü düzenler.</p>\n          </article>\n\n          <article class=\"card\">\n            <span class=\"number\">03</span>\n            <h3>JavaScript</h3>\n            <p>Butonlara ve diğer öğelere hareket ve davranış kazandırır.</p>\n          </article>\n        </div>\n      </section>\n    </main>\n\n    <footer>\n      <p>MacBook + merak + sabır ile hazırlandı.</p>\n    </footer>\n\n    <script src=\"script.js\"></script>\n  </body>\n</html>\n","contentType":"text/html; charset=UTF-8"},"/style.css":{"body":":root {\n  color-scheme: dark;\n  --background: #071a1a;\n  --surface: #0d2927;\n  --surface-light: #123633;\n  --text: #f5f2e9;\n  --muted: #b4c8c2;\n  --accent: #7dd3fc;\n  --accent-dark: #23170a;\n  --line: rgba(245, 242, 233, 0.13);\n}\n\n* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  min-height: 100vh;\n  background:\n    radial-gradient(circle at 82% 10%, rgba(255, 180, 92, 0.12), transparent 28rem),\n    var(--background);\n  color: var(--text);\n  font-family: Inter, ui-sans-serif, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif;\n}\n\n.page-shell {\n  width: min(1100px, calc(100% - 40px));\n  margin: 0 auto;\n}\n\n.hero {\n  display: grid;\n  align-content: center;\n  min-height: 72vh;\n  padding: 80px 0 64px;\n}\n\n.eyebrow {\n  margin: 0 0 18px;\n  color: var(--accent);\n  font-size: 0.76rem;\n  font-weight: 800;\n  letter-spacing: 0.16em;\n}\n\nh1,\nh2,\nh3,\np {\n  text-wrap: pretty;\n}\n\nh1 {\n  max-width: 820px;\n  margin: 0;\n  font-size: clamp(3.4rem, 10vw, 7.7rem);\n  line-height: 0.91;\n  letter-spacing: -0.065em;\n}\n\nh1 span {\n  color: var(--accent);\n}\n\n.intro {\n  max-width: 650px;\n  margin: 34px 0 0;\n  color: var(--muted);\n  font-size: clamp(1.1rem, 2.4vw, 1.45rem);\n  line-height: 1.65;\n}\n\nbutton {\n  width: fit-content;\n  margin-top: 34px;\n  padding: 15px 22px;\n  border: 0;\n  border-radius: 999px;\n  background: var(--accent);\n  color: var(--accent-dark);\n  font: inherit;\n  font-weight: 800;\n  cursor: pointer;\n  transition: transform 180ms ease, box-shadow 180ms ease;\n}\n\nbutton:hover {\n  transform: translateY(-2px);\n  box-shadow: 0 12px 32px rgba(255, 180, 92, 0.2);\n}\n\nbutton:focus-visible {\n  outline: 3px solid var(--text);\n  outline-offset: 4px;\n}\n\nbutton.completed {\n  background: var(--text);\n}\n\n.message {\n  min-height: 1.5em;\n  margin: 14px 0 0;\n  color: var(--muted);\n}\n\n.learning {\n  padding: 80px 0 100px;\n  border-top: 1px solid var(--line);\n}\n\n.section-heading {\n  display: grid;\n  grid-template-columns: 0.7fr 1.3fr;\n  align-items: end;\n  gap: 28px;\n  margin-bottom: 42px;\n}\n\nh2 {\n  max-width: 640px;\n  margin: 0;\n  font-size: clamp(2rem, 5vw, 4.2rem);\n  line-height: 1;\n  letter-spacing: -0.045em;\n}\n\n.card-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 16px;\n}\n\n.card {\n  min-height: 250px;\n  padding: 26px;\n  border: 1px solid var(--line);\n  border-radius: 22px;\n  background: linear-gradient(145deg, var(--surface-light), var(--surface));\n}\n\n.number {\n  display: inline-block;\n  margin-bottom: 60px;\n  color: var(--accent);\n  font-size: 0.8rem;\n  font-weight: 800;\n}\n\nh3 {\n  margin: 0 0 10px;\n  font-size: 1.45rem;\n}\n\n.card p {\n  margin: 0;\n  color: var(--muted);\n  line-height: 1.65;\n}\n\nfooter {\n  padding: 24px 20px;\n  border-top: 1px solid var(--line);\n  color: var(--muted);\n  text-align: center;\n}\n\n@media (max-width: 760px) {\n  .page-shell {\n    width: min(100% - 28px, 1100px);\n  }\n\n  .hero {\n    min-height: auto;\n    padding-top: 90px;\n  }\n\n  .section-heading,\n  .card-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .card {\n    min-height: auto;\n  }\n\n  .number {\n    margin-bottom: 42px;\n  }\n}\n","contentType":"text/css; charset=UTF-8"},"/script.js":{"body":"const celebrateButton = document.querySelector(\"#celebrate-button\");\nconst message = document.querySelector(\"#message\");\n\ncelebrateButton.addEventListener(\"click\", () => {\n  celebrateButton.textContent = \"Harika bir başlangıç! ✓\";\n  celebrateButton.classList.add(\"completed\");\n  message.textContent = \"Bu butonu Ali Efe JavaScript ile çalıştırdı! 🚀\";\n});\n","contentType":"text/javascript; charset=UTF-8"}};

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const file = files[url.pathname];

    if (!file) {
      return new Response("Sayfa bulunamadı.", {
        status: 404,
        headers: { "Content-Type": "text/plain; charset=UTF-8" },
      });
    }

    return new Response(file.body, {
      headers: {
        "Content-Type": file.contentType,
        "X-Content-Type-Options": "nosniff",
      },
    });
  },
};
